package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testSetDateFormat_ShouldSetDatePatternAndReturnThis() throws Exception {
    String pattern = "yyyy-MM-dd";

    GsonBuilder returned = gsonBuilder.setDateFormat(pattern);

    // Verify the returned instance is the same
    assertSame(gsonBuilder, returned);

    // Use reflection to verify private field datePattern is set correctly
    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    String actualPattern = (String) datePatternField.get(gsonBuilder);
    assertEquals(pattern, actualPattern);
  }

  @Test
  public void testSetDateFormat_WithEmptyString_ShouldSetDatePattern() throws Exception {
    String pattern = "";

    GsonBuilder returned = gsonBuilder.setDateFormat(pattern);

    assertSame(gsonBuilder, returned);

    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    String actualPattern = (String) datePatternField.get(gsonBuilder);
    assertEquals(pattern, actualPattern);
  }

  @Test
  public void testSetDateFormat_WithNull_ShouldSetDatePatternToNull() throws Exception {
    String pattern = null;

    GsonBuilder returned = gsonBuilder.setDateFormat(pattern);

    assertSame(gsonBuilder, returned);

    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    String actualPattern = (String) datePatternField.get(gsonBuilder);
    assertNull(actualPattern);
  }
}
